        setFilter: function (filter) {
            let activeObject = this.canvas.getActiveObject()
            if (!activeObject) return
            if (activeObject.type !== 'image') return
            activeObject.filters = []
            if (filter === 'greyscale') {
                activeObject.filters.push(new fabric.Image.filters.Grayscale());
            }
            if (filter === 'technicolor') {
                activeObject.filters.push(new fabric.Image.filters.Technicolor());
            }
            if (filter === 'kodachrome') {
                activeObject.filters.push(new fabric.Image.filters.Kodachrome());
            }
            if (filter === 'vintage') {
                activeObject.filters.push(new fabric.Image.filters.Vintage());
            }
            if (filter === 'red') {
                activeObject.filters.push(new fabric.Image.filters.BlendColor({
                    color: 'red',
                    mode: 'add',
                    alpha: 0.4
                }));
            }
            if (filter === 'yellow') {
                activeObject.filters.push(new fabric.Image.filters.BlendColor({
                    color: 'yellow',
                    mode: 'add',
                    alpha: 0.4
                }));
            }
            activeObject.applyFilters();
        },
        setAlign: function (align) {
            this.canvas.alignActiveObject(align)
            this.canvas.requestRenderAll()
        },
        setStyle: function (style) {
            if (!this.activeSelection) return
            for (const property in style) {
                if (style[property] === null) {
                    delete style[property]
                }
            }
            if (style.textAlign) {
                const positions = ["left", "center", "right", "left"];
                const currentIndex = positions.findIndex((v) => v === style.textAlign);
                style.textAlign = positions[currentIndex + 1]
            }
            this.canvas.getActiveObject().set(style)
            if (this.canvas.getMissingFonts().length > 0 && style.fontFamily) {
                this.canvas.fire('missing:fonts', this.canvas.getMissingFonts())
            }
            this.canvas.fire('object:modified', {
                target: this.canvas.getActiveObject()
            })
            this.canvas.requestRenderAll()
